mapper.select:
		SELECT *
    	FROM
    	(
    		SELECT ROW_NUMBER() OVER(ORDER BY ${sidx} ${sord}) RowNo, a.*
    		FROM (
				SELECT seleniumKeyNum, seleniumTitle, seleniumAddress, seleniumDetailNote, seleniumGroupName, seleniumGroupFullPath, seleniumGroupParentPath
				FROM selenium

			) a
		) b
    	WHERE b.RowNo between (1+(${page} - 1 ) * ${rows}) and (${page} * ${rows});
